-- SQL Server Seed/Test Data Script
-- This script inserts realistic test data into the tables generated by your EF Core model.
-- Assumptions:
--   - Tables are already created via EF Core migrations (e.g., Patients, LabParameters, LabRequests, LabReports, Notifications).
--   - Enum values are stored as integers (default EF Core behavior):
--     - Gender: 0 = Male, 1 = Female
--     - BloodGroup: 0 = A_Positive, 1 = A_Negative, 2 = B_Positive, 3 = B_Negative, 4 = AB_Positive, 5 = AB_Negative, 6 = O_positive, 7 = O_negative
--     - LabRequestState: 0 = Pending, 1 = Completed
--   - LabParameter represents real medical tests (e.g., blood, urine, etc.)—I've used realistic examples like Hemoglobin (blood), Glucose (blood/urine), etc.
--   - Data is interconnected to satisfy relationships (e.g., LabRequests linked to Patients, Notifications to LabReports).
--   - Inserting ~5-10 records per table for a good test dataset.
--   - Run this in SQL Server Management Studio (SSMS) or via your DatabaseManagementService if adapted.

-- Disable FK checks temporarily to allow inserts in any order (optional, but helpful for seeding)
SET NOCOUNT ON;
ALTER TABLE [LabRequests] NOCHECK CONSTRAINT ALL;
ALTER TABLE [LabReports] NOCHECK CONSTRAINT ALL;
ALTER TABLE [Notifications] NOCHECK CONSTRAINT ALL;

-- 1. Insert into LabParameters (standalone table with realistic medical test parameters)

-- 2. Insert into Patients (base table with realistic patient data)

-- 3. Insert into LabRequests (links to Patients, with realistic request states)
-- Assuming Patient IDs start from 1 (auto-generated IDENTITY)

-- 4. Insert into LabReports (links to Patients and optional LabRequests, with sample content)
-- Content is simplified text (e.g., results); in reality, this could be JSON or detailed reports.

-- 5. Insert into Notifications (links to LabReports, with realistic messages)

-- Re-enable FK checks
ALTER TABLE [LabRequests] CHECK CONSTRAINT ALL;
ALTER TABLE [LabReports] CHECK CONSTRAINT ALL;
ALTER TABLE [Notifications] CHECK CONSTRAINT ALL;

-- Optional: Verify inserts
SELECT * FROM [LabParameters];
SELECT * FROM [Patients];
SELECT * FROM [LabRequests];
SELECT * FROM [LabReports];
SELECT * FROM [Notifications];